window.SLIDES = [{"index":1,"folder":"01_Intro","name":"Intro","items":[{"type":"image","name":"Bellas_Artes_01.jpg","src":"/Slides_Datasets/01_Intro/Bellas_Artes_01.jpg"},{"type":"image","name":"image (11).png","src":"/Slides_Datasets/01_Intro/image%20(11).png"},{"type":"text","name":"intro.txt","text":"INSIDE THE BLACK BOX\nSchmidgen, on Simondon's politics of technology.\n\nA machine arrives polished and mute.\nWe admire the surface. We never open it.\n\"First a gothic cathedral, then a kitchen.\" (Barthes)\n\nThis canvas is the inside of the box:\nraw, scattered, unrationalized.\nYour job begins here.\n"}]},{"index":2,"folder":"02_Cybernetics_1951","name":"Cybernetics 1951","items":[{"type":"image","name":"208d16c370bf56f9a8c46c6cc52c2af4.jpg","src":"/Slides_Datasets/02_Cybernetics_1951/208d16c370bf56f9a8c46c6cc52c2af4.jpg"},{"type":"image","name":"a2677bbb325b8e2a0e4b47dd56720fe3.jpg","src":"/Slides_Datasets/02_Cybernetics_1951/a2677bbb325b8e2a0e4b47dd56720fe3.jpg"},{"type":"text","name":"note.txt","text":"THE FASCINATION ERROR\n\nThe 1950s adored robots and \"mechanical slaves.\"\nSimondon: this is a misunderstanding of progress.\n\nAutomation is not perfection.\nA machine that decides everything is a CLOSED machine.\nWorship of the closed object = the black box, sealed shut.\n"}]},{"index":3,"folder":"03_Open_Machine","name":"Open Machine","items":[{"type":"image","name":"acaa07f2c716566650ed0808b3377611.jpg","src":"/Slides_Datasets/03_Open_Machine/acaa07f2c716566650ed0808b3377611.jpg"},{"type":"image","name":"c831460ae1196453bb728464584709cd.jpg","src":"/Slides_Datasets/03_Open_Machine/c831460ae1196453bb728464584709cd.jpg"},{"type":"text","name":"note.txt","text":"OPENNESS, NOT AUTOMATION\n\n\"The criterion of technical perfection is\nopenness and flexibility, not automation.\" — Simondon\n\nThe good machine keeps a margin of indetermination:\na gap where information can still enter,\nwhere a human can still tune, regulate, interpret.\n\nOpen the box. Keep it open.\n"}]},{"index":4,"folder":"04_Democratic_Orchestra","name":"Democratic Orchestra","items":[{"type":"image","name":"cfddfb47e1c237de6a6e1737e2949999.jpg","src":"/Slides_Datasets/04_Democratic_Orchestra/cfddfb47e1c237de6a6e1737e2949999.jpg"},{"type":"text","name":"note.txt","text":"THE HUMAN AS CONDUCTOR\n\n\"Man is among the machines that work with him.\"\n\nNot master, not slave — interpreter.\nThe permanent organizer of an orchestra of open machines,\ntuning the relationships between them.\n\nThis is a cultural task. A political one.\n"}]},{"index":5,"folder":"05_Black-Boxed_Interfaces","name":"Black Boxed Interfaces","items":[{"type":"image","name":"bf5892ce2d1c1184904c9a69a691e4af.jpg","src":"/Slides_Datasets/05_Black-Boxed_Interfaces/bf5892ce2d1c1184904c9a69a691e4af.jpg"},{"type":"image","name":"d9a9dd58cf583efc63a4a324696fec4b.jpg","src":"/Slides_Datasets/05_Black-Boxed_Interfaces/d9a9dd58cf583efc63a4a324696fec4b.jpg"},{"type":"text","name":"warning.txt","text":"THE TODAY PROBLEM\n\nOur screens are gorgeous and sealed.\nReady-made, black-boxed interfaces.\nThey please us — and deny us the margin to regulate them.\n\nThe black box came back, glossier than ever.\nSo: who rationalizes the data now?\nYou. And the machine you are about to question.\n"}]},{"index":6,"folder":"06_End","name":"End","items":[{"type":"image","name":"image (3).jpg","src":"/Slides_Datasets/06_End/image%20(3).jpg"},{"type":"text","name":"warning.txt","text":"THE TODAY PROBLEM\n\nOur screens are gorgeous and sealed.\nReady-made, black-boxed interfaces.\nThey please us — and deny us the margin to regulate them.\n\nThe black box came back, glossier than ever.\nSo: who rationalizes the data now?\nYou. And the machine you are about to question.\n"}]}];
